import sys
input = sys.stdin.readline

def query(q):
    print(q, flush=True)
    return int(input())

n, k = map(int, input().split())

ors = [0] * (n + 1)
ands = [0] * (n + 1)

for i in range(2, n + 1):
    ors[i] = query(f"or 1 {i}")
    ands[i] = query(f"and 1 {i}")

free = ors[2] ^ ands[2]
bits = []
tmp = free
while tmp:
    bits.append(tmp & (-tmp))
    tmp &= tmp - 1

candidates = []
for mask in range(1 << len(bits)):
    s = 0
    for b in range(len(bits)):
        if mask & (1 << b):
            s |= bits[b]
    candidates.append(ands[2] | s)

valid = []
for c in candidates:
    ok = True
    for i in range(2, n + 1):
        ai = (ors[i] & ~c) | ands[i]
        if (c | ai) != ors[i] or (c & ai) != ands[i]:
            ok = False
            break
    if ok:
        valid.append(c)

results = []
for a1 in valid:
    arr = [a1]
    for i in range(2, n + 1):
        arr.append((ors[i] & ~a1) | ands[i])
    arr.sort()
    results.append(arr[k-1])

print(f"finish {results[0]}", flush=True)

